import Link from "next/link";
import type { Metrics, Analysis } from "@/lib/cockpit";
import { Badge, Sev, Sparkline, ScreenShot } from "@/app/_components/ui";
import { ControlRoom } from "@/app/_components/control-room";
import { RunTrigger } from "@/app/_components/run-trigger";
import { Zoomable } from "@/app/_components/zoomable";

type Mem = { screens: any[]; behaviors: any[]; skills: any[]; learnedAt?: string };

function fmtTime(ms: number): string {
  if (ms < 1000) return `${ms}ms`;
  const s = ms / 1000;
  if (s < 60) return `${s.toFixed(1)}s`;
  return `${Math.floor(s / 60)}m ${Math.round(s % 60)}s`;
}

// The cockpit's live "Overview" — KPIs, the watch-it-think control room, and the
// expandable analyses list. Unchanged behaviour, lifted out of the page so it can sit
// beside the Tree tab.
export function OverviewTab({ m, mem, analyses }: { m: Metrics; mem: Mem; analyses: Analysis[] }) {
  const replaySpeed = m.routeMs != null ? `${m.routeMs}ms` : "—";
  const cachedMs = m.routeMs ?? 447;

