      <div style={{ fontFamily: "var(--mono)", fontSize: 10, letterSpacing: ".1em", color: "var(--faint)" }}>{label}</div>
      <div
        style={{
          fontFamily: "var(--display)",
          fontWeight: 700,
          fontSize: 38,
          lineHeight: 1,
          marginTop: 12,
          color: opts?.valueColor,
        }}
      >
        {value}
      </div>
      <div style={{ fontSize: 12.5, color: opts?.subColor ?? "var(--muted-3)", marginTop: 10 }}>{sub}</div>
    </div>
  );

  return (
    <div>
      <h2 style={{ fontFamily: "var(--display)", fontWeight: 700, fontSize: 28, letterSpacing: "-.02em", margin: 0 }}>
        Overview
      </h2>
      <p style={{ color: "var(--muted-2)", fontSize: 15, lineHeight: 1.55, margin: "9px 0 0" }}>
        How the system is learning <b style={{ color: "var(--ink-2)" }}>slab10000/test-app</b> and getting faster — live.
      </p>

      {/* KPI ROW */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginTop: 24 }}>
        {kpiCard("REPLAY SPEED", replaySpeed, "0 model calls · cached route replay", { subColor: "var(--green)" })}
        {kpiCard("SCREENS LEARNED", m.screens, "explored with Computer Use", {
          border: "rgba(var(--accent-rgb),.3)",
          valueColor: "var(--accent-2)",
