"use client";
import { useEffect, useMemo, useRef, useState, type CSSProperties } from "react";
import type { TreeData, TreePR, TreeMain } from "@/lib/cockpit";
import { Badge, Sev, ScreenShot } from "@/app/_components/ui";
import { Zoomable } from "@/app/_components/zoomable";

/* ============================================================
   Tree tab — a git-graph of main + open PRs on the left, and an
   inspector on the right that renders either the learned `main`
   memory or a selected PR's review. Ported from the Claude Design
   "auto-qa Cockpit v2.dc.html", wired to real .autoqa data, using
   the cockpit's own design tokens. (Merge / Request-changes buttons
   intentionally omitted.)
   ============================================================ */

const PANEL_W = 440;
const ROW_H = 82;
const TOP = 12;
const LANE_X = [52, 104, 156]; // lane 0 = main spine, 1/2 = PR branch columns
const MAIN_VAR = "var(--accent)"; // teal accent spine = main, like the design
const MAIN_HEX = "#37d6b0";
const PR_VAR = ["#f6a64a", "#9b8bff", "#5ac8fa"]; // per-PR branch hues (2D / css)
const PR_HEX = ["#f6a64a", "#9b8bff", "#5ac8fa"]; // per-PR branch hues (3D / three.js)

type Row = {
  id: string;
  kind: "main" | "pr" | "hist";
  lane: number;
  idx: number;
  hueVar: string;
  hueHex: string;
  chip: string;
  title: string;
  sub: string;
  verdict: string;
  selectable: boolean;
  target: string;
  activeId: string;
  branchFrom?: string; // (PR rows) the spine node this branch curves out of
};

function verdictColor(v: string): string {
  const u = (v || "").toUpperCase();
  if (u === "FAIL") return "var(--red)";
  if (u === "PASS") return "var(--green)";
  if (u === "WARN" || u === "NEEDS_REVIEW") return "var(--amber)";
  return "var(--muted-3)";
}

function buildRows(data: TreeData): Row[] {
  const c = data.main.counts;
  const repoShort = data.repo.split("/")[1] || data.repo;

  // The lane-0 spine, top→bottom: the current baseline (HEAD) then the history that
  // produced it. Open PRs are stacked above it and all branch out of the single `main`
  // HEAD node (multiple branches from the same commit).
  const spine: Row[] = [
    {
      id: "main", kind: "main", lane: 0, idx: 0, hueVar: MAIN_VAR, hueHex: MAIN_HEX,
      chip: "main", title: "Current baseline",
      sub: `${c.screens} screens · ${c.contracts} contracts · ${c.skills} skills`,
      verdict: "HEAD", selectable: true, target: "main", activeId: "main",
    },
    {
      id: "main-onboard", kind: "hist", lane: 0, idx: 0, hueVar: MAIN_VAR, hueHex: MAIN_HEX,
      chip: "", title: `Onboarded ${repoShort}`,
      sub: `learned ${c.screens} screens · ${c.routes} routes`,
      verdict: "", selectable: false, target: "main", activeId: "",
    },
    {
      id: "main-init", kind: "hist", lane: 0, idx: 0, hueVar: MAIN_VAR, hueHex: MAIN_HEX,
      chip: "", title: `Connected ${data.repo}`,
      sub: "repo linked · baseline captured",
      verdict: "", selectable: false, target: "main", activeId: "",
    },
  ];

  // Newest PR on top (latest first), so the graph reads top→bottom like a commit history.
  const prsByRecency = [...data.prs].sort((a, b) => b.num - a.num);
  const prNodes: Row[] = prsByRecency.map((p, i) => ({
    id: p.id, kind: "pr", lane: 1 + (i % 2), idx: 0,
    hueVar: PR_VAR[i % PR_VAR.length], hueHex: PR_HEX[i % PR_HEX.length],
    chip: p.branch || p.id,
    title: `#${p.num} · ${p.title}`,
    sub: `${p.verdict} · ${p.classification || "—"}${p.took ? ` · ${p.took}` : ""}`,
    verdict: p.verdict, selectable: true, target: p.id, activeId: p.id,
    branchFrom: "main", // every open PR branches off the SAME main HEAD commit
  }));

  // Stack the PRs (newest first) above the main spine; each one branches out of the single
  // `main` node, so the graph shows multiple branches originating from the same commit.
  const rows: Row[] = [...prNodes, ...spine];
  rows.forEach((r, i) => (r.idx = i));
  return rows;
}

const cy = (i: number) => TOP + i * ROW_H + ROW_H / 2;

export function TreeView({ data }: { data: TreeData }) {
  const [sel, setSel] = useState<string>("main");
  const [mode, setMode] = useState<"2d" | "3d">("2d");
  const rows = useMemo(() => buildRows(data), [data]);
  const pr = data.prs.find((p) => p.id === sel) || null;
  const onSelect = (target: string) => setSel(target);
  const gh = TOP + rows.length * ROW_H + 6;

  return (
    <div style={{ display: "flex", gap: 22, alignItems: "flex-start" }}>
      {/* ============ GRAPH PANEL ============ */}
      <aside
        style={{
          flex: `0 0 ${PANEL_W}px`,
          position: "sticky",
          top: 14,
          alignSelf: "flex-start",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
          <span style={{ fontFamily: "var(--mono)", fontSize: 11, letterSpacing: ".12em", color: "var(--faint)" }}>GRAPH</span>
          <span style={{ fontSize: 12, color: "var(--muted-3)" }}>
            main + {data.prs.length} open PR{data.prs.length === 1 ? "" : "s"}
          </span>
          <span style={{ flex: 1 }} />
          <div style={{ display: "inline-flex", border: "1px solid var(--line)", borderRadius: 9, overflow: "hidden" }}>
            {(["2d", "3d"] as const).map((mdv) => (
              <button
                key={mdv}
                type="button"
                onClick={() => setMode(mdv)}
                style={{
                  fontFamily: "var(--mono)",
                  fontSize: 10.5,
                  letterSpacing: ".04em",
                  padding: "5px 10px",
                  border: "none",
                  cursor: "pointer",
                  background: mode === mdv ? "rgba(var(--accent-rgb),.16)" : "transparent",
                  color: mode === mdv ? "var(--accent-ink)" : "var(--faint)",
                }}
              >
                {mdv === "2d" ? "2D graph" : "3D orbit"}
              </button>
            ))}
          </div>
        </div>

        <div style={{ overflow: "hidden" }}>
          {mode === "2d" ? (
            <Graph2D rows={rows} sel={sel} onSelect={onSelect} height={gh} />
          ) : (
            <Graph3D rows={rows} sel={sel} onSelect={onSelect} />
          )}
          <div style={{ textAlign: "center", fontFamily: "var(--mono)", fontSize: 10.5, color: "var(--faint)", padding: "0 0 14px" }}>
            {mode === "2d" ? "click a node to inspect →" : "drag to orbit · scroll to zoom · click a node"}
          </div>
        </div>
      </aside>

      {/* ============ INSPECTOR ============ */}
      <main style={{ flex: 1, minWidth: 0 }}>
        {sel === "main" ? <MainInspector main={data.main} /> : pr ? <PRInspector pr={pr} repo={data.repo} /> : null}
      </main>
    </div>
  );
}

/* ---------------- 2D graph ---------------- */

function Graph2D({ rows, sel, onSelect, height }: { rows: Row[]; sel: string; onSelect: (t: string) => void; height: number }) {
  const idxById: Record<string, number> = {};
  rows.forEach((r) => (idxById[r.id] = r.idx));
  const spineRows = rows.filter((r) => r.lane === 0);
  const sFirst = spineRows.length ? spineRows[0].idx : 0;
  const sLast = spineRows.length ? spineRows[spineRows.length - 1].idx : 0;
  const edges: { d: string; c: string; w: number; o: number }[] = [];
  // main spine (lane 0): one straight vertical line through baseline + history nodes
  edges.push({ d: `M${LANE_X[0]} ${cy(sFirst)} L${LANE_X[0]} ${cy(sLast)}`, c: MAIN_VAR, w: 2.5, o: 0.55 });
  // each PR branches (short curve) from the spine node directly below it
  rows
    .filter((r) => r.kind === "pr")
    .forEach((r) => {
      const fromIdx = r.branchFrom != null && idxById[r.branchFrom] != null ? idxById[r.branchFrom] : sFirst;
      const x = LANE_X[r.lane];
      const a = cy(fromIdx);
      const b = cy(r.idx);
      const mid = (a + b) / 2;
      edges.push({ d: `M${LANE_X[0]} ${a} C${LANE_X[0]} ${mid} ${x} ${mid} ${x} ${b}`, c: r.hueVar, w: 2.5, o: 0

